<?php if (!$totals['items']): ?><div class="empty-state compact"><p>Coșul tău așteaptă prima alegere.</p><a class="button" href="<?= e(url('/shop')) ?>">Descoperă colecția</a></div><?php else: ?><div class="drawer-items"><?php foreach ($totals['items'] as $item): ?><div class="drawer-item"><img src="<?= e(url($item['image_path'])) ?>" alt="" width="72" height="86"><div><strong><?= e($item['name']) ?></strong><small><?= e($item['variant_label'] ?: 'Standard') ?> · <?= (int)$item['quantity'] ?> buc.</small></div><b><?= money((int)$item['price_minor']*(int)$item['quantity']) ?></b></div><?php endforeach; ?></div><div class="drawer-total"><span>Subtotal</span><strong><?= money($totals['subtotal_minor']) ?></strong></div><a class="button" href="<?= e(url('/checkout')) ?>">Finalizează comanda</a><a class="button button-outline" href="<?= e(url('/cos')) ?>">Vezi coșul</a><?php endif; ?>

